#!/usr/bin/env python3
from __future__ import annotations

import csv
import html
import json
from datetime import datetime
from pathlib import Path
from typing import Any

import incident_registry as incident_registry_mod
import pandas as pd
from risk_intervention_log import ensure_log_header, write_intervention_audit_report
from runtime_state_schema import TRADING_STATUS_PRIORITY, get_runtime_truth, trading_status_to_cn

PROJECT_ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = PROJECT_ROOT / "research" / "reports"
MARKET_PRICE_HISTORY = PROJECT_ROOT.parents[1] / "data" / "a_stock_history.csv"

TRACKED_ACCOUNT_PROFILES = [
    "defensive",
    "balanced",
    "aggressive",
    "exit_dual",
    "exit_tight",
    "alpha55",
]
RECONCILIATION_PROFILE_SLUGS = ["defensive", "balanced", "aggressive"]


def resolve_primary_trading_status(*truths: dict[str, Any]) -> dict[str, Any]:
    selected_status = "TRADING_ALLOWED"
    selected_reason = ""
    selected_source = ""
    for truth in truths:
        if not isinstance(truth, dict):
            continue
        status = str(truth.get("trading_status") or "").strip().upper()
        if not status:
            continue
        if TRADING_STATUS_PRIORITY.get(status, -1) >= TRADING_STATUS_PRIORITY.get(selected_status, -1):
            selected_status = status
            selected_reason = str(truth.get("trading_status_reason") or truth.get("state_reason") or "").strip()
            selected_source = str(truth.get("source") or "").strip()
    return {
        "status": selected_status,
        "label_cn": trading_status_to_cn(selected_status),
        "reason": selected_reason,
        "source": selected_source,
    }


def load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def load_csv_tail(path: Path, limit: int = 5) -> list[dict[str, Any]]:
    if not path.exists():
        return []

    with path.open("r", encoding="utf-8-sig", newline="") as f:
        rows = list(csv.DictReader(f))
    return rows[-limit:]


def load_csv_rows(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    with path.open("r", encoding="utf-8-sig", newline="") as f:
        return list(csv.DictReader(f))


def file_state(path: Path, stale_hours: int = 24) -> dict[str, Any]:
    if not path.exists():
        return {"status": "RED", "path": str(path), "mtime": "", "reason": "missing"}
    mtime = datetime.fromtimestamp(path.stat().st_mtime)
    age_hours = (datetime.now() - mtime).total_seconds() / 3600.0
    status = "GREEN" if age_hours <= stale_hours else "YELLOW"
    return {
        "status": status,
        "path": str(path),
        "mtime": mtime.strftime("%Y-%m-%d %H:%M:%S"),
        "reason": f"age_hours={age_hours:.1f}",
    }


def _parse_dt_safe(text: Any) -> datetime | None:
    value = str(text or "").strip()
    if not value:
        return None
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M", "%Y-%m-%d"):
        try:
            return datetime.strptime(value, fmt)
        except Exception:
            continue
    return None


def _normalize_date_tag(value: Any) -> str:
    text = str(value or "").strip()
    if len(text) == 8 and text.isdigit():
        return text
    if len(text) == 10 and text[4] == "-" and text[7] == "-":
        compact = text.replace("-", "")
        if len(compact) == 8 and compact.isdigit():
            return compact
    return ""


def normalize_breadth_alert_state(alert: dict[str, Any], *, expected_trade_date_tag: str) -> dict[str, Any]:
    if not isinstance(alert, dict) or not alert:
        return {
            "status": "NO_DATA",
            "issues": [{"code": "STALE_ALERT_DATA", "severity": "YELLOW", "detail": "missing_breadth_alert_state"}],
            "stale": True,
            "stale_reason": "missing_breadth_alert_state",
        }

    normalized = dict(alert)
    raw_issues = normalized.get("issues") or []
    issues: list[dict[str, Any]] = []
    for item in raw_issues:
        if isinstance(item, dict):
            issues.append(dict(item))

    stale_reasons: list[str] = []
    signal_date_tag = _normalize_date_tag(normalized.get("signal_date"))
    captured_dt = _parse_dt_safe(normalized.get("captured_at"))

    if expected_trade_date_tag and signal_date_tag and signal_date_tag != expected_trade_date_tag:
        stale_reasons.append(
            f"signal_date_mismatch:{signal_date_tag}!={expected_trade_date_tag}"
        )
    elif expected_trade_date_tag and not signal_date_tag:
        stale_reasons.append("missing_signal_date")

    if captured_dt is None:
        stale_reasons.append("missing_captured_at")
    else:
        age_hours = (datetime.now() - captured_dt).total_seconds() / 3600.0
        if age_hours > 8:
            stale_reasons.append(f"captured_at_stale:{age_hours:.1f}h")

    if stale_reasons:
        existing_codes = {str(item.get("code") or "") for item in issues}
        if "STALE_ALERT_DATA" not in existing_codes:
            issues.append(
                {
                    "code": "STALE_ALERT_DATA",
                    "severity": "YELLOW",
                    "detail": "; ".join(stale_reasons),
                }
            )
        normalized["status"] = "YELLOW"

    normalized["issues"] = issues
    normalized["stale"] = bool(stale_reasons)
    normalized["stale_reason"] = "; ".join(stale_reasons) if stale_reasons else "fresh"
    return normalized


def latest_report(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern))
    return files[-1] if files else None


def extract_date_tag_from_name(path: Path | None) -> str:
    if path is None:
        return ""
    stem = path.stem
    for part in reversed(stem.split("_")):
        if len(part) == 8 and part.isdigit():
            return part
    return ""


def resolve_expected_trade_date(report_date_tag: str) -> dict[str, str]:
    normalized = str(report_date_tag or "").strip()
    candidates: list[tuple[str, str]] = []

    if MARKET_PRICE_HISTORY.exists():
        try:
            frame = pd.read_csv(MARKET_PRICE_HISTORY, usecols=["trade_date"])
            trade_dates = pd.to_numeric(frame["trade_date"], errors="coerce").dropna()
            if not trade_dates.empty:
                latest_market_trade_date = str(int(trade_dates.max()))
                if latest_market_trade_date <= normalized:
                    candidates.append(("market_price_history", latest_market_trade_date))
        except Exception:
            pass

    today_report = load_json(REPORT_DIR / "today_stock_strategy_report_latest.json")
    today_report_date_tag = str(today_report.get("date_tag") or "").strip()
    if len(today_report_date_tag) == 8 and today_report_date_tag.isdigit() and today_report_date_tag <= normalized:
        candidates.append(("today_stock_strategy_report", today_report_date_tag))

    latest_live_review_tag = extract_date_tag_from_name(latest_report("live_close_review_v2_*.json"))
    if len(latest_live_review_tag) == 8 and latest_live_review_tag.isdigit() and latest_live_review_tag <= normalized:
        candidates.append(("live_close_review", latest_live_review_tag))

    for profile_slug in TRACKED_ACCOUNT_PROFILES:
        account_payload = load_json(REPORT_DIR / f"paper_{profile_slug}_account_v1_latest.json")
        account_date_tag = str(account_payload.get("date_tag") or "").strip()
        if len(account_date_tag) == 8 and account_date_tag.isdigit() and account_date_tag <= normalized:
            candidates.append((f"paper_account:{profile_slug}", account_date_tag))

    if not candidates:
        return {"date_tag": normalized, "source": "wall_clock"}

    source, date_tag = max(candidates, key=lambda item: item[1])
    return {"date_tag": date_tag, "source": source}


def governance_gate_state() -> dict[str, Any]:
    path = REPORT_DIR / "strategy_governance_gate_latest.json"
    if not path.exists():
        return {
            "status": "RED",
            "path": str(path),
            "mtime": "",
            "reason": "missing_governance_gate_report",
            "report_status": "MISSING",
            "blocking_issues": ["missing_governance_gate_report"],
            "registry_rows": [],
        }

    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {
            "status": "RED",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": "invalid_governance_gate_report",
            "report_status": "INVALID",
            "blocking_issues": ["invalid_governance_gate_report"],
            "registry_rows": [],
        }

    mtime = datetime.fromtimestamp(path.stat().st_mtime)
    age_hours = (datetime.now() - mtime).total_seconds() / 3600.0
    report_status = str(payload.get("overall_status") or "UNKNOWN").upper()
    blocking_issues = [str(x).strip() for x in (payload.get("blocking_issues") or []) if str(x).strip()]
    stale = age_hours > 72
    if stale:
        blocking_issues.append("stale_governance_gate_report")
    status = "GREEN" if report_status == "PASS" and not blocking_issues else "RED"
    if blocking_issues:
        reason = f"blocking:{blocking_issues[0]}"
    elif report_status == "PASS":
        reason = "ok"
    else:
        reason = f"report_status={report_status.lower()}"
    return {
        "status": status,
        "path": str(path),
        "mtime": mtime.strftime("%Y-%m-%d %H:%M:%S"),
        "reason": reason,
        "report_status": report_status,
        "blocking_issues": blocking_issues,
        "registry_rows": payload.get("registry_rows") or [],
        "generated_at": str(payload.get("generated_at") or ""),
    }


def incident_registry_state() -> dict[str, Any]:
    path = REPORT_DIR / "incident_registry_latest.json"
    weekly_path = REPORT_DIR / "incident_weekly_review_latest.json"
    if not path.exists():
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": "",
            "reason": "missing_incident_registry",
        }
    payload = load_json(path)
    mtime = datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
    open_count = int(payload.get("open_incident_count_30d") or 0)
    if not weekly_path.exists():
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": mtime,
            "reason": "missing_incident_weekly_review",
        }
    status = "GREEN" if str(payload.get("overall_status") or "").upper() == "PASS" and open_count == 0 else "YELLOW"
    return {
        "status": status,
        "path": str(path),
        "mtime": mtime,
        "reason": "ok" if status == "GREEN" else f"incident_open_count={open_count}",
    }


def event_watch_refresh_state(expected_date_tag: str) -> dict[str, Any]:
    path = REPORT_DIR / "runtime_risk_state_latest.json"
    if not path.exists():
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": "",
            "reason": "missing_runtime_risk_state",
        }
    payload = load_json(path)
    report_date = str(payload.get("date_tag") or "").strip()
    event_watch = payload.get("event_watch_refresh") or {}
    if report_date and report_date != expected_date_tag:
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": f"stale_event_watch_state:{report_date}",
        }
    if not isinstance(event_watch, dict) or not event_watch:
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": "missing_event_watch_refresh",
        }
    if bool(event_watch.get("ok")):
        return {
            "status": "GREEN",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": "ok",
        }
    return {
        "status": "RED",
        "path": str(path),
        "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
        "reason": f"event_watch_refresh_failed:returncode={event_watch.get('returncode')}",
    }


def live_chain_failure_state(expected_date_tag: str) -> dict[str, Any]:
    path = REPORT_DIR / "live_chain_failure_summary_latest.json"
    if not path.exists():
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": "",
            "reason": "missing_live_chain_failure_summary",
        }
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {
            "status": "RED",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": "invalid_live_chain_failure_summary",
        }
    summary_date = str(payload.get("date_tag") or "")
    if summary_date and summary_date != expected_date_tag:
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": f"stale_live_chain_failure_summary:{summary_date}",
        }
    return {
        "status": str(payload.get("overall_status") or "YELLOW"),
        "path": str(path),
        "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(payload.get("reason") or "ok"),
    }


def manual_review_closure_alert_state(expected_date_tag: str) -> dict[str, Any]:
    path = REPORT_DIR / "manual_review_closure_alert_latest.json"
    if not path.exists():
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": "",
            "reason": "missing_manual_review_closure_alert",
        }
    payload = load_json(path)
    report_date = str(payload.get("date_tag") or "")
    if report_date and report_date != expected_date_tag:
        return {
            "status": "YELLOW",
            "path": str(path),
            "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": f"stale_manual_review_closure_alert:{report_date}",
        }
    return {
        "status": str(payload.get("overall_status") or "YELLOW"),
        "path": str(path),
        "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(payload.get("reason") or "ok"),
    }


def _is_blank(value: Any) -> bool:
    text = str(value or "").strip()
    return text == "" or text.lower() == "nan"


def manual_review_file_state(path: Path | None) -> dict[str, Any]:
    if path is None:
        return {
            "status": "RED",
            "path": "",
            "mtime": "",
            "reason": "missing_reconciliation_file",
            "completed": False,
            "pending_items": ["missing_reconciliation_file"],
            "reviewer": "",
        }
    if not path.exists():
        return {
            "status": "RED",
            "path": str(path),
            "mtime": "",
            "reason": "missing_reconciliation_file",
            "completed": False,
            "pending_items": ["missing_reconciliation_file"],
            "reviewer": "",
        }

    rows = load_csv_rows(path)
    mtime = datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
    if not rows:
        return {
            "status": "RED",
            "path": str(path),
            "mtime": mtime,
            "reason": "empty_reconciliation_file",
            "completed": False,
            "pending_items": ["empty_reconciliation_file"],
            "reviewer": "",
        }

    pending_items: list[str] = []
    reviewer = ""
    for row in rows:
        section = str(row.get("section") or "").strip()
        item = str(row.get("item") or "").strip()
        if section not in {"人工复核", "结论"}:
            continue
        status = str(row.get("status") or "").strip().upper()
        value = str(row.get("value") or "").strip()
        if item == "复核人" and (not _is_blank(value)):
            reviewer = value
        if status in {"", "TODO", "AUTO"} or _is_blank(value):
            pending_items.append(item or "unknown")

    completed = len(pending_items) == 0
    reason = "ok" if completed else f"pending:{'|'.join(pending_items)}"
    return {
        "status": "GREEN" if completed else "RED",
        "path": str(path),
        "mtime": mtime,
        "reason": reason,
        "completed": completed,
        "pending_items": pending_items,
        "reviewer": reviewer,
    }


def aggregate_manual_review_state() -> dict[str, Any]:
    profiles: list[dict[str, Any]] = []
    for slug in RECONCILIATION_PROFILE_SLUGS:
        state = manual_review_file_state(latest_report(f"paper_{slug}_daily_reconciliation_*.csv"))
        state["profile_slug"] = slug
        profiles.append(state)

    pending_profiles = [x["profile_slug"] for x in profiles if x["status"] != "GREEN"]
    reason = "ok" if not pending_profiles else f"pending_profiles:{'|'.join(pending_profiles)}"
    return {
        "status": "GREEN" if not pending_profiles else "RED",
        "path": ",".join(x["path"] for x in profiles if x.get("path")),
        "mtime": "",
        "reason": reason,
        "profiles": profiles,
        "pending_profiles": pending_profiles,
        "completed": not pending_profiles,
    }


def intervention_log_state(runtime_state: dict[str, Any]) -> dict[str, Any]:
    path = REPORT_DIR / "risk_intervention_log.csv"
    ensure_log_header(path)
    audit = write_intervention_audit_report(payload=runtime_state, log_path=path, report_dir=REPORT_DIR)
    audit_path = Path(str(audit.get("latest_path") or ""))
    mtime = ""
    if audit_path.exists():
        mtime = datetime.fromtimestamp(audit_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
    return {
        "status": str(audit.get("status") or "RED"),
        "path": str(audit.get("latest_path") or path),
        "mtime": mtime,
        "reason": str(audit.get("reason") or "unknown"),
    }


def resolve_nextday_handoff_state(
    live_review: dict[str, Any],
    *,
    expected_date_tag: str,
) -> dict[str, Any]:
    handoff = live_review.get("nextday_manual_sell_handoff")
    handoff_path = ""
    payload: dict[str, Any] = {}
    if isinstance(handoff, dict):
        handoff_path = str(handoff.get("json_path") or "").strip()
        if handoff_path:
            path = Path(handoff_path)
            if path.exists():
                payload = load_json(path)
            else:
                payload = {}
        else:
            payload = handoff

    if not payload:
        candidate = REPORT_DIR / f"live_nextday_manual_sell_handoff_{expected_date_tag}.json"
        if candidate.exists():
            payload = load_json(candidate)
            handoff_path = str(candidate)

    ack = payload.get("receiver_ack") or {}
    ack_status = str(ack.get("status") or "").strip().upper()
    ack_owner = str(ack.get("owner") or "").strip()
    ack_time = str(ack.get("timestamp") or "").strip()
    ack_action = str(ack.get("action") or "").strip()
    acked = ack_status in {"ACKED", "DONE", "CONFIRMED"} and bool(ack_owner) and bool(ack_time) and bool(ack_action)

    return {
        "exists": bool(payload),
        "path": handoff_path,
        "ack_status": ack_status or "PENDING",
        "acked": acked,
        "ack_owner": ack_owner,
        "ack_timestamp": ack_time,
        "ack_action": ack_action,
        "issues": payload.get("issues") if isinstance(payload.get("issues"), list) else [],
    }


def live_execution_integrity_state(
    live_review: dict[str, Any],
    live_review_path: Path | None,
    *,
    expected_date_tag: str,
) -> dict[str, Any]:
    review_date_tag = str(live_review.get("date_tag") or "").strip()
    if not review_date_tag:
        return {
            "status": "RED",
            "path": str(live_review_path) if live_review_path else "",
            "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
            "reason": "invalid_close_review_schema:missing_date_tag",
        }
    if "issues" not in live_review:
        return {
            "status": "RED",
            "path": str(live_review_path) if live_review_path else "",
            "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
            "reason": "invalid_close_review_schema:missing_issues",
        }
    if live_review_path and review_date_tag != expected_date_tag:
        return {
            "status": "YELLOW",
            "path": str(live_review_path),
            "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "reason": f"stale_live_close_review:{review_date_tag}",
        }

    orders_total = int(((live_review.get("orders") or {}).get("total")) or 0)
    execution_attempted = int(((live_review.get("orders") or {}).get("execution_attempted")) or 0)
    pending_confirm_not_sent = int(((live_review.get("orders") or {}).get("pending_confirm_not_sent")) or 0)
    not_sent = int(((live_review.get("orders") or {}).get("not_sent")) or 0)
    queue_resolution = (live_review.get("queue_resolution") or {}) if isinstance(live_review, dict) else {}
    queue_status = str(queue_resolution.get("status") or "").strip()
    journal_records = int(((live_review.get("journal") or {}).get("records")) or 0)
    path = str(live_review_path) if live_review_path else ""
    handoff_state = resolve_nextday_handoff_state(live_review, expected_date_tag=expected_date_tag)
    if execution_attempted > 0 and journal_records <= 0:
        return {
            "status": "RED",
            "path": path,
            "mtime": "",
            "reason": "orders_without_journal_records",
        }
    if orders_total > 0 and execution_attempted <= 0 and journal_records <= 0:
        if not handoff_state.get("exists"):
            return {
                "status": "RED",
                "path": path,
                "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
                "reason": "orders_pending_without_execution_missing_handoff",
            }
        if not handoff_state.get("acked"):
            return {
                "status": "RED",
                "path": str(handoff_state.get("path") or path),
                "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
                "reason": "orders_pending_without_execution_unacknowledged",
            }
    if (
        orders_total > 0
        and execution_attempted <= 0
        and journal_records <= 0
        and queue_status in {"closed_pending_user_confirm_queue", "already_closed_pending_queue"}
        and handoff_state.get("acked")
    ):
        return {
            "status": "GREEN",
            "path": path,
            "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
            "reason": "reviewed_pending_user_confirm_queue",
        }
    if orders_total > 0 and execution_attempted <= 0 and journal_records <= 0:
        return {
            "status": "YELLOW",
            "path": path,
            "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if live_review_path else "",
            "reason": "orders_pending_not_sent",
        }
    if not live_review_path:
        return {
            "status": "YELLOW",
            "path": "",
            "mtime": "",
            "reason": "missing_live_close_review",
        }
    return {
        "status": "GREEN",
        "path": path,
        "mtime": datetime.fromtimestamp(live_review_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
        "reason": "ok",
    }


def profile_update_state(profile_slug: str, *, expected_date_tag: str) -> dict[str, Any]:
    account_path = REPORT_DIR / f"paper_{profile_slug}_account_v1_latest.json"
    if not account_path.exists():
        return {
            "status": "RED",
            "profile_slug": profile_slug,
            "latest_date_tag": "",
            "expected_date_tag": expected_date_tag,
            "reason": "missing_account_latest",
        }
    try:
        payload = json.loads(account_path.read_text(encoding="utf-8"))
    except Exception:
        return {
            "status": "RED",
            "profile_slug": profile_slug,
            "latest_date_tag": "",
            "expected_date_tag": expected_date_tag,
            "reason": "invalid_account_json",
        }
    latest_date_tag = str(payload.get("date_tag") or "").strip()
    return {
        "status": "GREEN" if latest_date_tag == expected_date_tag else "RED",
        "profile_slug": profile_slug,
        "latest_date_tag": latest_date_tag,
        "expected_date_tag": expected_date_tag,
        "reason": "ok" if latest_date_tag == expected_date_tag else f"stale_profile_date={latest_date_tag}",
    }


def build_execution_layer_snapshot(
    live_review: dict[str, Any],
    live_review_path: Path | None,
    *,
    expected_date_tag: str,
) -> dict[str, Any]:
    empty_snapshot = {
        "live_risk_level": "NO_DATA",
        "live_tomorrow_mode": "-",
        "live_runtime_truth_state": "NO_DATA",
        "live_runtime_truth_ready": False,
        "trading_status": "NO_DATA",
        "trading_status_reason": "missing_same_day_live_close_review",
        "live_orders_total": 0,
        "live_execution_attempted": 0,
        "live_pending_confirm_not_sent": 0,
        "live_not_sent": 0,
        "live_journal_records": 0,
        "source_report": str(live_review_path) if live_review_path else "",
        "source_report_date_tag": "",
    }
    if not live_review_path:
        return empty_snapshot

    review_date_tag = str(live_review.get("date_tag") or "").strip()
    if not review_date_tag:
        snapshot = dict(empty_snapshot)
        snapshot["trading_status_reason"] = "invalid_same_day_live_close_review_schema:missing_date_tag"
        return snapshot
    if review_date_tag != expected_date_tag:
        snapshot = dict(empty_snapshot)
        snapshot["trading_status_reason"] = f"stale_same_day_live_close_review:{review_date_tag}"
        snapshot["source_report_date_tag"] = review_date_tag
        return snapshot

    runtime_truth = get_runtime_truth(live_review)
    return {
        "live_risk_level": live_review.get("risk_level", "NO_DATA"),
        "live_tomorrow_mode": live_review.get("tomorrow_mode", "-"),
        "live_runtime_truth_state": str(runtime_truth.get("state") or "NO_DATA"),
        "live_runtime_truth_ready": bool(runtime_truth.get("trading_ready")),
        "trading_status": str(runtime_truth.get("trading_status") or "NO_DATA"),
        "trading_status_reason": str(runtime_truth.get("trading_status_reason") or ""),
        "live_orders_total": (live_review.get("orders") or {}).get("total", 0),
        "live_execution_attempted": (live_review.get("orders") or {}).get("execution_attempted", 0),
        "live_pending_confirm_not_sent": (live_review.get("orders") or {}).get("pending_confirm_not_sent", 0),
        "live_not_sent": (live_review.get("orders") or {}).get("not_sent", 0),
        "live_journal_records": (live_review.get("journal") or {}).get("records", 0),
        "source_report": str(live_review_path),
        "source_report_date_tag": review_date_tag,
    }


def build_payload() -> dict[str, Any]:
    expected_report_date_tag = datetime.now().strftime("%Y%m%d")
    expected_trade_date = resolve_expected_trade_date(expected_report_date_tag)
    expected_trade_date_tag = expected_trade_date["date_tag"]
    incident_registry_mod.sync_registry(write=True)
    today_report = load_json(REPORT_DIR / "today_stock_strategy_report_latest.json")
    premarket_reviews = sorted(REPORT_DIR.glob("live_premarket_risk_v2_*.json"))
    premarket_review_path = premarket_reviews[-1] if premarket_reviews else None
    premarket_review = load_json(premarket_review_path) if premarket_review_path else {}
    guard_summary = load_json(REPORT_DIR / "strategy_probe_guard_summary_latest.json")
    perf_panel = load_json(REPORT_DIR / "strategy_performance_panel_latest.json")
    breadth_alert_raw = load_json(REPORT_DIR / "breadth_strict_oos_alert_state.json")
    breadth_alert = normalize_breadth_alert_state(
        breadth_alert_raw,
        expected_trade_date_tag=expected_trade_date_tag,
    )
    runtime_state = load_json(REPORT_DIR / "runtime_risk_state_latest.json")
    future_leak_audit = load_json(REPORT_DIR / "future_leak_walkforward_audit_latest.json")
    intervention_rows = load_csv_tail(REPORT_DIR / "risk_intervention_log.csv", limit=5)
    profile_update_checks = [profile_update_state(profile_slug, expected_date_tag=expected_trade_date_tag) for profile_slug in TRACKED_ACCOUNT_PROFILES]
    exact_live_review_path = REPORT_DIR / f"live_close_review_v2_{expected_trade_date_tag}.json"
    latest_live_review_path = latest_report("live_close_review_v2_*.json")
    live_review_path = exact_live_review_path if exact_live_review_path.exists() else latest_live_review_path
    live_review = load_json(live_review_path) if live_review_path else {}
    execution_live_review_path = exact_live_review_path if exact_live_review_path.exists() else None
    execution_live_review = load_json(execution_live_review_path) if execution_live_review_path else {}
    exit_suite_reports = sorted(REPORT_DIR.glob("paper_exit_candidate_suite_*.json"))
    manual_review_summary = aggregate_manual_review_state()
    governance_summary = governance_gate_state()

    system_checks = {
        "strategy_report": file_state(REPORT_DIR / "today_stock_strategy_report_latest.json", stale_hours=72),
        "premarket_runtime_v2": file_state(premarket_review_path, stale_hours=72) if premarket_review_path else {"status": "YELLOW", "path": "", "mtime": "", "reason": "missing"},
        "strategy_governance_gate": {
            "status": governance_summary["status"],
            "path": governance_summary["path"],
            "mtime": governance_summary["mtime"],
            "reason": governance_summary["reason"],
        },
        "guard_summary": file_state(REPORT_DIR / "strategy_probe_guard_summary_latest.json", stale_hours=72),
        "performance_panel": file_state(REPORT_DIR / "strategy_performance_panel_latest.html", stale_hours=72),
        "breadth_aggressive": file_state(REPORT_DIR / "breadth_aggressive_paper_latest.json", stale_hours=72),
        "breadth_strict_oos": file_state(REPORT_DIR / "breadth_strict_oos_paper_latest.json", stale_hours=72),
        "breadth_strict_oos_alert": file_state(REPORT_DIR / "breadth_strict_oos_alert_state.json", stale_hours=72),
        "alpha55_account": file_state(REPORT_DIR / "paper_alpha55_account_v1_latest.json", stale_hours=72),
        "exit_dual_account": file_state(REPORT_DIR / "paper_exit_dual_account_v1_latest.json", stale_hours=72),
        "exit_tight_account": file_state(REPORT_DIR / "paper_exit_tight_account_v1_latest.json", stale_hours=72),
        "exit_candidate_suite": file_state(exit_suite_reports[-1], stale_hours=72) if exit_suite_reports else {"status": "RED", "path": "", "mtime": "", "reason": "missing"},
        "future_leak_walkforward_audit": file_state(REPORT_DIR / "future_leak_walkforward_audit_latest.json", stale_hours=72),
        "risk_intervention_log": intervention_log_state(runtime_state),
        "manual_reconciliation": {
            "status": manual_review_summary["status"],
            "path": manual_review_summary["path"],
            "mtime": manual_review_summary["mtime"],
            "reason": manual_review_summary["reason"],
        },
        "manual_review_closure_alert": manual_review_closure_alert_state(expected_report_date_tag),
        "incident_registry": incident_registry_state(),
        "event_watch_refresh": event_watch_refresh_state(expected_trade_date_tag),
        "live_chain_failures": live_chain_failure_state(expected_trade_date_tag),
        "live_execution_integrity": live_execution_integrity_state(
            live_review,
            live_review_path,
            expected_date_tag=expected_trade_date_tag,
        ),
        "comparison_dashboard": file_state(REPORT_DIR / "paper_profiles_comparison_latest.html", stale_hours=72),
        "portal": file_state(REPORT_DIR / "dashboard_portal_latest.html", stale_hours=72),
    }
    if future_leak_audit and not bool(future_leak_audit.get("passed", False)):
        system_checks["future_leak_walkforward_audit"]["status"] = "RED"
        system_checks["future_leak_walkforward_audit"]["reason"] = "audit_failed"

    statuses = [x["status"] for x in system_checks.values()]
    statuses.extend(item["status"] for item in profile_update_checks)
    overall = "GREEN"
    if "RED" in statuses:
        overall = "RED"
    elif "YELLOW" in statuses:
        overall = "YELLOW"

    strategy_layer = {
        "risk_mode": today_report.get("risk_mode", "-"),
        "risk_off": bool(today_report.get("risk_off", False)),
        "hard_stop": bool(today_report.get("hard_stop", False)),
        "runtime_truth_state": str(get_runtime_truth(runtime_state).get("state") or "NO_DATA"),
        "runtime_truth_ready": bool(get_runtime_truth(runtime_state).get("trading_ready")),
        "trading_status": str(get_runtime_truth(runtime_state).get("trading_status") or "FULL_HALT"),
        "trading_status_reason": str(get_runtime_truth(runtime_state).get("trading_status_reason") or ""),
        "manual_intervention_active": any(
            str(x) in {"manual_hard_stop", "manual_risk_off"}
            for x in ((runtime_state.get("latest_runtime") or {}).get("gate_reasons") or [])
        ),
        "manual_intervention_reason": str((runtime_state.get("latest_runtime") or {}).get("halt_reason") or ""),
        "guard_portfolio_status": guard_summary.get("portfolio_status", "NO_DATA"),
        "guard_halt_count": guard_summary.get("halt_count", 0),
        "manual_review_complete": bool(manual_review_summary.get("completed")),
