        "report_date_tag": expected_report_date_tag,
        "expected_trade_date_tag": expected_trade_date_tag,
        "expected_trade_date_source": expected_trade_date["source"],
        "expected_date_tag": expected_trade_date_tag,
        "profile_updates": profile_update_checks,
    }

    execution_layer = build_execution_layer_snapshot(
        execution_live_review,
        execution_live_review_path,
        expected_date_tag=expected_trade_date_tag,
    )

    profit_layer = {
        "profiles": perf_panel.get("rows", []),
        "breadth_alert": {
            "status": breadth_alert.get("status", "NO_DATA"),
            "issue_codes": [str(x.get("code", "")) for x in (breadth_alert.get("issues") or []) if x.get("code")],
            "actual_position_pct": breadth_alert.get("actual_position_pct"),
            "target_position_pct": breadth_alert.get("target_position_pct"),
            "target_drift_pct": breadth_alert.get("target_drift_pct"),
            "daily_nav_change_pct": breadth_alert.get("daily_nav_change_pct"),
            "max_drawdown_pct": breadth_alert.get("max_drawdown_pct"),
            "captured_at": breadth_alert.get("captured_at", ""),
            "signal_date": breadth_alert.get("signal_date", ""),
            "stale": bool(breadth_alert.get("stale", False)),
            "stale_reason": str(breadth_alert.get("stale_reason") or ""),
        },
        "future_leak_audit": {
            "passed": bool(future_leak_audit.get("passed", False)) if future_leak_audit else None,
            "issues": future_leak_audit.get("issues", []) if future_leak_audit else [],
            "window_count": future_leak_audit.get("aggressive_window_count"),
        },
        "recent_interventions": intervention_rows,
        "manual_review_summary": manual_review_summary,
        "premarket_runtime_truth": premarket_review.get("runtime_truth") or {},
        "governance_summary": governance_summary,
    }

    primary_trading_status = resolve_primary_trading_status(
        get_runtime_truth(runtime_state),
        get_runtime_truth(execution_live_review),
    )

    return {
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "overall_status": overall,
        "system_health_status": overall,
        "market_risk_status": {
            "portfolio_status": strategy_layer["guard_portfolio_status"],
            "risk_mode": strategy_layer["risk_mode"],
            "risk_off": strategy_layer["risk_off"],
            "hard_stop": strategy_layer["hard_stop"],
            "trading_status": strategy_layer["trading_status"],
            "trading_status_reason": strategy_layer["trading_status_reason"],
        },
        "trade_execution_status": {
            "status": execution_layer["trading_status"],
            "reason": execution_layer["trading_status_reason"],
            "risk_level": execution_layer["live_risk_level"],
            "orders_total": execution_layer["live_orders_total"],
            "execution_attempted": execution_layer["live_execution_attempted"],
            "journal_records": execution_layer["live_journal_records"],
        },
        "trading_status": primary_trading_status,
        "system_checks": system_checks,
        "strategy_layer": strategy_layer,
        "execution_layer": execution_layer,
        "profit_layer": profit_layer,
    }


def render_html(payload: dict[str, Any]) -> str:
    status_rank = {"RED": 0, "YELLOW": 1, "GREEN": 2, "NO_DATA": 3}
    system_rows = []
    for name, item in payload["system_checks"].items():
        system_rows.append(
            f"<tr><td>{html.escape(name)}</td><td><span class='pill {item['status'].lower()}'>{html.escape(item['status'])}</span></td>"
            f"<td>{html.escape(item['mtime'])}</td><td>{html.escape(item['reason'])}</td><td><code>{html.escape(item['path'])}</code></td></tr>"
        )

    sorted_profiles = sorted(
        payload["profit_layer"]["profiles"],
        key=lambda row: (
            status_rank.get(str(row.get("status") or "NO_DATA"), 3),
            float(row.get("drawdown_pct", 0.0)),
            float(row.get("total_return_pct", 0.0)),
            str(row.get("profile_slug") or ""),
        ),
    )

    profile_rows = []
    profile_cards = []
    for row in sorted_profiles:
        profile_rows.append(
            f"<tr><td>{html.escape(row['profile_slug'])}</td><td>{html.escape(row['status'])}</td><td>{html.escape(str(row['tomorrow_mode']))}</td>"
            f"<td>{row['nav']:.2f}</td><td>{row['total_return_pct']:.2f}%</td><td>{row['drawdown_pct']:.2f}%</td><td>{html.escape(row['issue_codes'] or 'none')}</td></tr>"
        )
        status_class = {
            "GREEN": "status-green",
            "YELLOW": "status-yellow",
            "RED": "status-red",
        }.get(str(row["status"]), "")
        profile_cards.append(
            f"""<article class="card {status_class}">
              <div class="label">{html.escape(row['profile_slug'])}</div>
              <div class="value">{html.escape(str(row['status']))}</div>
              <div class="minor">mode={html.escape(str(row['tomorrow_mode']))} | issues={html.escape(row['issue_codes'] or 'none')}</div>
              <div class="metric-grid">
                <div><span>净值</span><strong>{row['nav']:.2f}</strong></div>
                <div><span>累计收益</span><strong>{row['total_return_pct']:.2f}%</strong></div>
                <div><span>回撤</span><strong>{row['drawdown_pct']:.2f}%</strong></div>
                <div><span>持仓数</span><strong>{int(row.get('position_count', 0))}</strong></div>
              </div>
            </article>"""
        )

    breadth_alert = payload["profit_layer"].get("breadth_alert", {}) or {}
    breadth_issue_codes = ",".join(breadth_alert.get("issue_codes") or []) or "none"
    breadth_alert_status = str(breadth_alert.get("status") or "NO_DATA")
    breadth_alert_card_class = {
        "GREEN": "status-green",
        "YELLOW": "status-yellow",
        "RED": "status-red",
    }.get(breadth_alert_status, "")
    breadth_alert_minor = (
        f"issues={html.escape(breadth_issue_codes)} | drift={html.escape(str(breadth_alert.get('target_drift_pct', '-')))}%"
    )
    governance_status = str(payload["strategy_layer"].get("governance_status") or "UNKNOWN")
    governance_card_class = "status-green" if governance_status == "PASS" else "status-red"
    governance_issues = payload["strategy_layer"].get("governance_blocking_issues") or []

    return f"""<!doctype html>
